class MetadataBuilder:
    """Builds gRPC metadata from HTTP headers and user input."""

    # Headers that should not be forwarded
    BLOCKED_HEADERS = {
        'host', 'content-length', 'transfer-encoding',
        'connection', 'keep-alive', 'upgrade'
    }

    # Prefix for custom headers to forward
    FORWARDED_PREFIXES = ('x-', 'grpc-', 'authorization', 'user-agent', 'accept-language')

    def __init__(self):
        self._metadata: List[Tuple[str, str]] = []

    def add(self, key: str, value: str) -> 'MetadataBuilder':
        """Add a single metadata entry."""
        sanitized_key = key.lower().strip()
        if sanitized_key and value is not None:
            self._metadata.append((sanitized_key, str(value).strip()))
        return self

    def add_from_dict(self, headers: Dict[str, str]) -> 'MetadataBuilder':
        """Add metadata from a dictionary of headers."""
        for key, value in headers.items():
            self.add(key, value)
        return self

    def add_from_http_headers(self, http_headers: Dict[str, str]) -> 'MetadataBuilder':
        """
        Filter and add HTTP headers as gRPC metadata.
        Only forwards allowed headers (custom x- headers, auth, etc.)
        """
        for key, value in http_headers.items():
            lower_key = key.lower().strip()

            # Skip blocked headers
            if lower_key in self.BLOCKED_HEADERS:
                continue

            # Only forward headers with allowed prefixes
            if any(lower_key.startswith(prefix) for prefix in self.FORWARDED_PREFIXES):
                self.add(lower_key, value)

        return self

    def add_request_id(self, request_id: str) -> 'MetadataBuilder':
        """Add a request/correlation ID for tracing."""
        return self.add('x-request-id', request_id)

    def add_auth_token(self, token: str) -> 'MetadataBuilder':
        """Add authorization token."""
        return self.add('authorization', f'Bearer {token}')

    def build(self) -> List[Tuple[str, str]]:
        """Build and return the metadata as a list of tuples."""
        return list(self._metadata)

    def clear(self) -> 'MetadataBuilder':
        """Clear all metadata."""
        self._metadata = []
        return self


