class ApiGatewayForwarder:
    """
    API Gateway service that forwards HTTP requests to backend gRPC services.
    Accepts custom headers and passes them as gRPC metadata.
    """

    def __init__(self):
        self._backend_clients: Dict[str, GrpcClientWrapper] = {}
        self._default_metadata: List[Tuple[str, str]] = [
            ('x-gateway-name', 'api-gateway-v1'),
            ('x-gateway-version', '1.0.0'),
        ]

    def register_backend(self, service_name: str, target: str,
                         secure: bool = False,
                         credentials: Optional[grpc.ChannelCredentials] = None):
        """Register a backend gRPC service."""
        client = GrpcClientWrapper(target, secure=secure, credentials=credentials)
        self._backend_clients[service_name] = client
        print(f"[Gateway] Registered backend service: {service_name} -> {target}")

    def unregister_backend(self, service_name: str):
        """Unregister and close a backend service connection."""
        if service_name in self._backend_clients:
            self._backend_clients[service_name].close()
            del self._backend_clients[service_name]
            print(f"[Gateway] Unregistered backend service: {service_name}")

    def build_metadata_from_request(self, http_headers: Dict[str, str],
                                     user_metadata: Optional[Dict[str, str]] = None,
                                     request_id: Optional[str] = None,
                                     auth_token: Optional[str] = None) -> List[Tuple[str, str]]:
        """
        Build gRPC metadata from HTTP request headers and additional user input.
        """
        builder = MetadataBuilder()

        # Add default gateway metadata
        builder.add_from_dict(dict(self._default_metadata))

        # Add filtered HTTP headers
        builder.add_from_http_headers(http_headers)

        # Add user-provided custom metadata
        if user_metadata:
            builder.add_from_dict(user_metadata)

        # Add request ID for tracing
        if request_id:
            builder.add_request_id(request_id)

        # Add auth token
        if auth_token:
            builder.add_auth_token(auth_token)

        return builder.build()

    def forward_unary_unary(self, service_name: str, method_path: str,
                            request_data: bytes,
                            http_headers: Dict[str, str],
                            user_metadata: Optional[Dict[str, str]] = None,
                            request_id: Optional[str] = None,
                            auth_token: Optional[str] = None,
                            timeout: float = 30.0) -> Tuple[bytes, List[Tuple[str, str]], grpc.StatusCode]:
        """
        Forward a unary-unary gRPC call to a backend service.

        Returns:
            Tuple of (response_data, trailing_metadata, status_code)
        """
        if service_name not in self._backend_clients:
            raise ValueError(f"Backend service '{service_name}' not registered")

        client = self._backend_clients[service_name]
        metadata = self.build_metadata_from_request(
            http_headers, user_metadata, request_id, auth_token
        )

        print(f"[Gateway] Forwarding request to {service_name}{method_path}")
        print(f"[Gateway] Metadata: {metadata}")

        # Create the unary-unary callable
        channel_callable = client.channel.unary_unary(
            method_path,
            request_serializer=None,  # Raw bytes
            response_deserializer=None,  # Raw bytes
        )

        try:
            # Make the call with metadata
            response, call = channel_callable.with_call(
                request_data,
                metadata=metadata,
                timeout=timeout,
            )

            trailing_metadata = list(call.trailing_metadata())
            status_code = call.code()

            print(f"[Gateway] Response status: {status_code}")
            print(f"[Gateway] Trailing metadata: {trailing_metadata}")

            return response, trailing_metadata, status_code

        except grpc.RpcError as e:
            print(f"[Gateway] RPC Error: {e.code()} - {e.details()}")
            return b'', [], e.code()

    def close_all(self):
        """Close all backend connections."""
        for name in list(self._backend_clients.keys()):
            self.unregister_backend(name)


