class BackendServiceServicer(object):
    """A simple backend gRPC service that echoes metadata."""

    def ProcessRequest(self, request, context):
        """Process incoming request, log metadata, and set trailing metadata."""
        # Read incoming metadata
        incoming_metadata = dict(context.invocation_metadata())
        print(f"\n[Backend] Received request with metadata:")
        for key, value in incoming_metadata.items():
            print(f"  {key}: {value}")

        # Process the request
        request_payload = request if isinstance(request, bytes) else request.payload
        response_data = {
            'status': 'success',
            'received_metadata': incoming_metadata,
            'echo': request_payload.decode('utf-8') if isinstance(request_payload, bytes) else request_payload,
        }

        # Set trailing metadata on the response context
        trailing_metadata = [
            ('x-backend-processing-time', '42ms'),
            ('x-backend-node', 'node-1'),
            ('x-request-id', incoming_metadata.get('x-request-id', 'unknown')),
            ('x-trace-id', 'trace-abc123'),
        ]
        context.set_trailing_metadata(trailing_metadata)

        print(f"[Backend] Set trailing metadata: {trailing_metadata}")

        return json.dumps(response_data).encode('utf-8')


def create_backend_server(port: int = 50051) -> grpc.Server:
    """Create and configure the backend gRPC server."""
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))

    # Register the generic handler
    servicer = BackendServiceServicer()

    class GenericHandler(grpc.GenericRpcHandler):
        def service(self, handler_call_details):
            print(f"\n[Backend] Handling method: {handler_call_details.method}")
            return grpc.unary_unary_rpc_method_handler(
                servicer.ProcessRequest,
            )

    server.add_generic_rpc_handlers([GenericHandler()])
    server.add_insecure_port(f'[::]:{port}')
    return server


