class GatewayServiceServicer:
    """
    Gateway gRPC servicer that receives requests and forwards them
    to appropriate backend services, passing metadata through.
    """

    def __init__(self, forwarder: ApiGatewayForwarder):
        self.forwarder = forwarder

    def ForwardRequest(self, request, context):
        """
        Receive a gateway request, extract metadata, forward to backend,
        and set trailing metadata from the backend response.
        """
        # Extract incoming metadata (simulating HTTP headers)
        incoming_metadata = dict(context.invocation_metadata())
        print(f"\n[GatewayServicer] Incoming metadata: {incoming_metadata}")

        # Determine target service from metadata
        target_service = incoming_metadata.get('x-target-service', 'user-service')
        target_method = incoming_metadata.get('x-target-method', '/backend.Service/Process')

        # Build HTTP-like headers from the incoming metadata
        http_headers = {k: v for k, v in incoming_metadata.items()}

        try:
            response_data, trailing_meta, status = self.forwarder.forward_unary_unary(
                service_name=target_service,
                method_path=target_method,
                request_data=request if isinstance(request, bytes) else request.SerializeToString(),
                http_headers=http_headers,
                request_id=incoming_metadata.get('x-request-id'),
                auth_token=incoming_metadata.get('authorization', '').replace('Bearer ', ''),
            )

            # Forward trailing metadata from backend to the caller
            if trailing_meta:
                # Add gateway-specific trailing metadata
                gateway_trailing = list(trailing_meta) + [
                    ('x-gateway-forwarded', 'true'),
                    ('x-upstream-service', target_service),
                ]
                context.set_trailing_metadata(gateway_trailing)
                print(f"[GatewayServicer] Set trailing metadata: {gateway_trailing}")

            return response_data

        except ValueError as e:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(str(e))
            context.set_trailing_metadata([
                ('x-error', 'service-not-found'),
                ('x-gateway-forwarded', 'false'),
            ])
            return b''

        except Exception as e:
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(f"Gateway error: {str(e)}")
            context.set_trailing_metadata([
                ('x-error', 'internal-gateway-error'),
                ('x-gateway-forwarded', 'false'),
            ])
            return b''


